// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

/**
 * @title CharityDonation
 * @dev Smart contract for managing transparent charity donations with on-chain records
 */
contract CharityDonation {
    // ══════════════════════════════════════════════════
    // STATE VARIABLES
    // ══════════════════════════════════════════════════
    
    address public owner;
    uint256 public totalDonationsReceived;
    uint256 public totalDonors;
    
    // Campaign structure
    struct Campaign {
        uint256 id;
        string name;
        string category;
        string description;
        address payable charityAddress;
        uint256 goalAmount;
        uint256 raisedAmount;
        uint256 createdAt;
        bool active;
    }
    
    // Donation structure
    struct Donation {
        uint256 id;
        address donor;
        uint256 campaignId;
        uint256 amount;
        string message;
        uint256 timestamp;
        bool processed;
    }
    
    // User structure
    struct User {
        address walletAddress;
        string username;
        uint256 totalDonated;
        uint256 donationCount;
        uint256 joinedAt;
    }
    
    // Mappings
    mapping(uint256 => Campaign) public campaigns;
    mapping(uint256 => Donation) public donations;
    mapping(address => User) public users;
    mapping(address => uint256[]) public userDonations;
    mapping(address => bool) public registeredUsers;
    
    uint256 public campaignCount;
    uint256 public donationCount;
    
    // ══════════════════════════════════════════════════
    // EVENTS
    // ══════════════════════════════════════════════════
    
    event CampaignCreated(
        uint256 indexed campaignId,
        string name,
        uint256 goalAmount,
        address indexed charityAddress
    );
    
    event DonationReceived(
        uint256 indexed donationId,
        uint256 indexed campaignId,
        address indexed donor,
        uint256 amount,
        string message,
        uint256 timestamp
    );
    
    event UserRegistered(
        address indexed userAddress,
        string username,
        uint256 timestamp
    );
    
    event CampaignGoalReached(
        uint256 indexed campaignId,
        uint256 totalRaised,
        uint256 timestamp
    );
    
    event FundsWithdrawn(
        address indexed charityAddress,
        uint256 amount,
        uint256 campaignId,
        uint256 timestamp
    );
    
    // ══════════════════════════════════════════════════
    // MODIFIERS
    // ══════════════════════════════════════════════════
    
    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner can call this function");
        _;
    }
    
    modifier campaignExists(uint256 _campaignId) {
        require(_campaignId > 0 && _campaignId <= campaignCount, "Campaign does not exist");
        _;
    }
    
    modifier isActiveCampaign(uint256 _campaignId) {
        require(campaigns[_campaignId].active, "Campaign is not active");
        _;
    }
    
    // ══════════════════════════════════════════════════
    // CONSTRUCTOR
    // ══════════════════════════════════════════════════
    
    constructor() {
        owner = msg.sender;
        campaignCount = 0;
        donationCount = 0;
        totalDonationsReceived = 0;
        totalDonors = 0;
    }
    
    // ══════════════════════════════════════════════════
    // USER MANAGEMENT
    // ══════════════════════════════════════════════════
    
    function registerUser(string calldata _username) external {
        require(!registeredUsers[msg.sender], "User already registered");
        require(bytes(_username).length > 0, "Username cannot be empty");
        require(bytes(_username).length <= 50, "Username too long");
        
        users[msg.sender] = User({
            walletAddress: msg.sender,
            username: _username,
            totalDonated: 0,
            donationCount: 0,
            joinedAt: block.timestamp
        });
        
        registeredUsers[msg.sender] = true;
        emit UserRegistered(msg.sender, _username, block.timestamp);
    }
    
    function getUser(address _userAddress) external view returns (User memory) {
        return users[_userAddress];
    }
    
    // ══════════════════════════════════════════════════
    // CAMPAIGN MANAGEMENT
    // ══════════════════════════════════════════════════
    
    function createCampaign(
        string calldata _name,
        string calldata _category,
        string calldata _description,
        address payable _charityAddress,
        uint256 _goalAmount
    ) external onlyOwner {
        require(_goalAmount > 0, "Goal amount must be greater than 0");
        require(_charityAddress != address(0), "Invalid charity address");
        require(bytes(_name).length > 0, "Campaign name cannot be empty");
        
        campaignCount++;
        campaigns[campaignCount] = Campaign({
            id: campaignCount,
            name: _name,
            category: _category,
            description: _description,
            charityAddress: _charityAddress,
            goalAmount: _goalAmount,
            raisedAmount: 0,
            createdAt: block.timestamp,
            active: true
        });
        
        emit CampaignCreated(campaignCount, _name, _goalAmount, _charityAddress);
    }
    
    function getCampaign(uint256 _campaignId) 
        external 
        view 
        campaignExists(_campaignId) 
        returns (Campaign memory) 
    {
        return campaigns[_campaignId];
    }
    
    function deactivateCampaign(uint256 _campaignId) 
        external 
        onlyOwner 
        campaignExists(_campaignId) 
    {
        campaigns[_campaignId].active = false;
    }
    
    // ══════════════════════════════════════════════════
    // DONATIONS
    // ══════════════════════════════════════════════════
    
    function donate(
        uint256 _campaignId,
        string calldata _message
    ) external payable campaignExists(_campaignId) isActiveCampaign(_campaignId) {
        require(msg.value > 0, "Donation amount must be greater than 0");
        
        // Register user if not already registered
        if (!registeredUsers[msg.sender]) {
            users[msg.sender] = User({
                walletAddress: msg.sender,
                username: "",
                totalDonated: 0,
                donationCount: 0,
                joinedAt: block.timestamp
            });
            registeredUsers[msg.sender] = true;
            totalDonors++;
        }
        
        // Create donation record
        donationCount++;
        donations[donationCount] = Donation({
            id: donationCount,
            donor: msg.sender,
            campaignId: _campaignId,
            amount: msg.value,
            message: _message,
            timestamp: block.timestamp,
            processed: false
        });
        
        // Update campaign raised amount
        campaigns[_campaignId].raisedAmount += msg.value;
        
        // Update user stats
        User storage user = users[msg.sender];
        user.totalDonated += msg.value;
        user.donationCount++;
        
        // Track user donations
        userDonations[msg.sender].push(donationCount);
        
        // Update total
        totalDonationsReceived += msg.value;
        
        // Check if goal reached
        if (campaigns[_campaignId].raisedAmount >= campaigns[_campaignId].goalAmount) {
            emit CampaignGoalReached(
                _campaignId,
                campaigns[_campaignId].raisedAmount,
                block.timestamp
            );
        }
        
        emit DonationReceived(
            donationCount,
            _campaignId,
            msg.sender,
            msg.value,
            _message,
            block.timestamp
        );
    }
    
    function getDonation(uint256 _donationId) external view returns (Donation memory) {
        require(_donationId > 0 && _donationId <= donationCount, "Donation does not exist");
        return donations[_donationId];
    }
    
    function getUserDonations(address _userAddress) external view returns (uint256[] memory) {
        return userDonations[_userAddress];
    }
    
    // ══════════════════════════════════════════════════
    // WITHDRAWAL & MANAGEMENT
    // ══════════════════════════════════════════════════
    
    function withdrawFunds(uint256 _campaignId) 
        external 
        campaignExists(_campaignId) 
        isActiveCampaign(_campaignId) 
    {
        Campaign storage campaign = campaigns[_campaignId];
        require(msg.sender == campaign.charityAddress || msg.sender == owner, "Not authorized");
        require(campaign.raisedAmount > 0, "No funds to withdraw");
        
        uint256 withdrawAmount = campaign.raisedAmount;
        campaign.raisedAmount = 0;
        
        (bool success, ) = campaign.charityAddress.call{value: withdrawAmount}("");
        require(success, "Withdrawal failed");
        
        emit FundsWithdrawn(campaign.charityAddress, withdrawAmount, _campaignId, block.timestamp);
    }
    
    function getContractBalance() external view returns (uint256) {
        return address(this).balance;
    }
    
    function getContractStats() external view returns (
        uint256 _totalDonations,
        uint256 _totalDonors,
        uint256 _activeCampaigns,
        uint256 _contractBalance
    ) {
        uint256 activeCampaigns = 0;
        for (uint256 i = 1; i <= campaignCount; i++) {
            if (campaigns[i].active) activeCampaigns++;
        }
        
        return (
            totalDonationsReceived,
            totalDonors,
            activeCampaigns,
            address(this).balance
        );
    }
    
    // Fallback function to receive ETH
    receive() external payable {}
}
